import{_ as a,o as t,c as o,a4 as r}from"./chunks/framework.CcEU2j4W.js";const u=JSON.parse('{"title":"Interface: DispatchEvent · ui","description":"","frontmatter":{"title":"Interface: DispatchEvent · ui"},"headers":[],"relativePath":"api/ui/interfaces/DispatchEvent.md","filePath":"api/ui/interfaces/DispatchEvent.md"}'),d={name:"api/ui/interfaces/DispatchEvent.md"};function s(i,e,c,n,l,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../">@jsvision/ui</a> / DispatchEvent</p><h1 id="interface-dispatchevent" tabindex="-1">Interface: DispatchEvent <a class="header-anchor" href="#interface-dispatchevent" aria-label="Permalink to &quot;Interface: DispatchEvent&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L127" target="_blank" rel="noreferrer">ui/src/view/types.ts:127</a></p><p>The envelope wrapped around each event before it is routed to views. This — not the raw read-only input event — is what <code>View.onEvent(ev)</code> receives. A handler reads the event and sets <code>handled</code> to consume it, and uses the optional seams below (<code>emit</code>, <code>focusView</code>, capture, clipboard, …) to act on the app. Those seams are present during real dispatch and <code>undefined</code> in a bare envelope you might construct in a test, so always call them optional-chained (<code>ev.emit?.(…)</code>).</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="clickcount" tabindex="-1">clickCount? <a class="header-anchor" href="#clickcount" aria-label="Permalink to &quot;clickCount?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>clickCount?</strong>: <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L139" target="_blank" rel="noreferrer">ui/src/view/types.ts:139</a></p><p>For a mouse-down, how many consecutive clicks landed on the same cell (1 = single, 2 = double, 3 = triple…). Present only on a mouse-down during real dispatch; <code>undefined</code> otherwise. A row widget that activates on double-click checks <code>ev.clickCount === 2</code>.</p><hr><h3 id="emit" tabindex="-1">emit? <a class="header-anchor" href="#emit" aria-label="Permalink to &quot;emit?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>emit?</strong>: (<code>command</code>, <code>arg?</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L144" target="_blank" rel="noreferrer">ui/src/view/types.ts:144</a></p><p>Raise a typed command onto the current dispatch tick — how a widget signals an action (e.g. a button emitting <code>&#39;ok&#39;</code>) for a menu/status/app handler to pick up.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="command" tabindex="-1">command <a class="header-anchor" href="#command" aria-label="Permalink to &quot;command&quot;">​</a></h5><p><code>string</code></p><h5 id="arg" tabindex="-1">arg? <a class="header-anchor" href="#arg" aria-label="Permalink to &quot;arg?&quot;">​</a></h5><p><code>unknown</code></p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="event" tabindex="-1">event <a class="header-anchor" href="#event" aria-label="Permalink to &quot;event&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>event</strong>: <a href="./../type-aliases/AppEvent.html"><code>AppEvent</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L129" target="_blank" rel="noreferrer">ui/src/view/types.ts:129</a></p><p>The wrapped decoded input event or internal command.</p><hr><h3 id="focusview" tabindex="-1">focusView? <a class="header-anchor" href="#focusview" aria-label="Permalink to &quot;focusView?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>focusView?</strong>: (<code>view</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L149" target="_blank" rel="noreferrer">ui/src/view/types.ts:149</a></p><p>Move focus to another view — used e.g. by a <code>Label</code> to focus the control it labels. A non-focusable target is a no-op.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view" tabindex="-1">view <a class="header-anchor" href="#view" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="getfocused" tabindex="-1">getFocused? <a class="header-anchor" href="#getfocused" aria-label="Permalink to &quot;getFocused?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>getFocused?</strong>: () =&gt; <a href="./../classes/View.html"><code>View</code></a> | <code>null</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L179" target="_blank" rel="noreferrer">ui/src/view/types.ts:179</a></p><p>The currently-focused view. A dropdown control saves it before opening its popup and restores it on dismiss.</p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><a href="./../classes/View.html"><code>View</code></a> | <code>null</code></p><hr><h3 id="handled" tabindex="-1">handled <a class="header-anchor" href="#handled" aria-label="Permalink to &quot;handled&quot;">​</a></h3><blockquote><p><strong>handled</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L131" target="_blank" rel="noreferrer">ui/src/view/types.ts:131</a></p><p>Set <code>true</code> by a handler to stop the event propagating to the remaining phases/views.</p><hr><h3 id="hascapture" tabindex="-1">hasCapture? <a class="header-anchor" href="#hascapture" aria-label="Permalink to &quot;hasCapture?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>hasCapture?</strong>: (<code>view</code>) =&gt; <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L162" target="_blank" rel="noreferrer">ui/src/view/types.ts:162</a></p><p>Whether <code>view</code> currently holds the pointer capture. A view mid-gesture (a window drag, a status press) checks this before applying a move, so if the capture was lost externally (a modal opened or closed mid-drag) the gesture aborts cleanly instead of jumping to the cursor.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view-1" tabindex="-1">view <a class="header-anchor" href="#view-1" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="local" tabindex="-1">local? <a class="header-anchor" href="#local" aria-label="Permalink to &quot;local?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>local?</strong>: <a href="./Point.html"><code>Point</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L133" target="_blank" rel="noreferrer">ui/src/view/types.ts:133</a></p><p>Mouse/wheel coordinates translated to this view&#39;s local cells; absent for keys and commands.</p><hr><h3 id="popuphost" tabindex="-1">popupHost? <a class="header-anchor" href="#popuphost" aria-label="Permalink to &quot;popupHost?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>popupHost?</strong>: <a href="./PopupHost.html"><code>PopupHost</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L184" target="_blank" rel="noreferrer">ui/src/view/types.ts:184</a></p><p>The overlay host a dropdown control mounts its anchored popup into. Present when an app shell (or a <code>Dialog</code>) has provided one; <code>undefined</code> in a headless/no-shell setup.</p><hr><h3 id="readclipboard" tabindex="-1">readClipboard? <a class="header-anchor" href="#readclipboard" aria-label="Permalink to &quot;readClipboard?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>readClipboard?</strong>: () =&gt; <code>string</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L174" target="_blank" rel="noreferrer">ui/src/view/types.ts:174</a></p><p>Read the application&#39;s in-app clipboard buffer (the last text copied or cut within the app). Used by editable controls for in-app paste without reading the external OS clipboard. Returns <code>&#39;&#39;</code> when nothing has been copied yet, and is <code>undefined</code> on an event that was not routed through the loop (e.g. one constructed directly in a test) — always call it optional-chained.</p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>string</code></p><hr><h3 id="releasecapture" tabindex="-1">releaseCapture? <a class="header-anchor" href="#releasecapture" aria-label="Permalink to &quot;releaseCapture?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>releaseCapture?</strong>: () =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L156" target="_blank" rel="noreferrer">ui/src/view/types.ts:156</a></p><p>Release the pointer capture; a no-op if none is set. Pairs with <a href="#setcapture">setCapture</a>.</p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="setcapture" tabindex="-1">setCapture? <a class="header-anchor" href="#setcapture" aria-label="Permalink to &quot;setCapture?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>setCapture?</strong>: (<code>view</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L154" target="_blank" rel="noreferrer">ui/src/view/types.ts:154</a></p><p>Capture the pointer to <code>view</code>: while captured, all mouse/wheel events route to <code>view</code> until <a href="#releasecapture">releaseCapture</a>. Used for drag gestures such as dragging a scrollbar thumb.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view-2" tabindex="-1">view <a class="header-anchor" href="#view-2" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="setclipboard" tabindex="-1">setClipboard? <a class="header-anchor" href="#setclipboard" aria-label="Permalink to &quot;setClipboard?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>setClipboard?</strong>: (<code>text</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/87c171dd634990729dec839e8ad9fe4d45eb6481/packages/ui/src/view/types.ts#L167" target="_blank" rel="noreferrer">ui/src/view/types.ts:167</a></p><p>Write <code>text</code> to the system clipboard — used by <code>Input</code> copy/cut. A no-op when the terminal has no clipboard support; the control never touches I/O directly.</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="text" tabindex="-1">text <a class="header-anchor" href="#text" aria-label="Permalink to &quot;text&quot;">​</a></h5><p><code>string</code></p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p>',102)])])}const b=a(d,[["render",s]]);export{u as __pageData,b as default};
